from string_utils.manipulation import compress

def test__compress():
    """
    Test that the compress function raises a ValueError when the compression_level is set to 0, which is invalid.
    The original function allows compression_level between 1 and 9, inclusive.
    Therefore, it should raise an exception with the mutant implementation that accepts 0 as a valid compression level.
    """
    try:
        compress('some string', compression_level=0)
    except ValueError as e:
        assert str(e) == 'Invalid compression_level: it must be an "int" between 0 and 9'
    else:
        raise AssertionError("Expected ValueError not raised")
